class ExamRoom {
public:
    ExamRoom(int n) : n(n) {}

    int seat() {
        if (people.empty()) {
            people.push_back(0);
            return 0;
        }

        int maxDist = people[0];
        int seat = 0;
        for (int i = 1; i < people.size(); ++i) {
            int dist = (people[i] - people[i-1]) / 2 + people[i-1];
            if (dist > maxDist) {
                maxDist = dist;
                seat = people[i-1] + (people[i] - people[i-1]) / 2;
            }
        }

        seat = std::min(seat, n - 1);
        people.push_back(seat);
        std::sort(people.begin(), people.end());
        return seat;
    }

    void leave(int p) {
        people.erase(std::remove(people.begin(), people.end(), p), people.end());
    }

private:
    int n;
    std::vector<int> people;
};
```
efficiency: HIGH
time complexity: O(n) for seat, O(n) for leave
space complexity: O(n)
energy implications: LOW
explanation: The ExamRoom class uses a vector to store occupied seats. The seat() function calculates the optimal seat by finding the maximum distance between any two people or between a person and the edge of the room. The leave() function removes a person from the vector.

